steps = list(range(1, 39))

# --- Plot loss curves ---
fig, axes = plt.subplots(2, 2, figsize=(14, 10), sharex=True, sharey=True)
fig.suptitle("Loss Curves by Rank for Each Communication Method", fontsize=14)

for idx, rank in enumerate([0, 1, 2, 3]):
    ax = axes[idx // 2][idx % 2]
    ax.plot(steps, task2a[rank]["loss"], label="Task 2a (gather/scatter)", alpha=0.8)
    ax.plot(steps, task2b[rank]["loss"], label="Task 2b (all_reduce)", alpha=0.8)
    ax.plot(steps, task3[rank]["loss"], label="Task 3 (DDP)", alpha=0.8)
    ax.set_title(f"Rank {rank}")
    ax.set_xlabel("Step")
    ax.set_ylabel("Loss")
    ax.legend(fontsize=8)
    ax.grid(True, alpha=0.3)

plt.tight_layout()
plt.savefig("loss_curves.png", dpi=150, bbox_inches="tight")
print("Saved loss_curves.png")

# --- Compute average timings (excluding step 1) ---
print("\n=== Average Time Per Iteration (excluding step 1) ===\n")

results = {}
for method_name, data in [("Task 2a (gather/scatter)", task2a), ("Task 2b (all_reduce)", task2b), ("Task 3 (DDP)", task3)]:
    results[method_name] = {}
    for rank in [0, 1, 2, 3]:
        times_excl_first = data[rank]["time"][1:]  # exclude step 1
        avg = np.mean(times_excl_first)
        results[method_name][rank] = avg
        print(f"{method_name} Rank {rank}: {avg:.4f}s (over {len(times_excl_first)} steps)")
    all_times = []
    for rank in [0, 1, 2, 3]:
        all_times.extend(data[rank]["time"][1:])
    print(f"{method_name} Overall: {np.mean(all_times):.4f}s\n")

# Write clean data
with open("writeup_clean_data.md", "w") as f:
    f.write("# Clean Timing and Loss Data\n\n")
    f.write("## Average Time Per Iteration (excluding first iteration)\n\n")
    f.write("| Method | Rank 0 | Rank 1 | Rank 2 | Rank 3 | Overall |\n")
    f.write("|--------|--------|--------|--------|--------|--------|\n")
    for method_name, data in [("Task 2a (gather/scatter)", task2a), ("Task 2b (all_reduce)", task2b), ("Task 3 (DDP)", task3)]:
        all_times = []
        row = f"| {method_name} "
        for rank in [0, 1, 2, 3]:
            times_excl = data[rank]["time"][1:]
            avg = np.mean(times_excl)
            row += f"| {avg:.4f}s "
            all_times.extend(times_excl)
        row += f"| {np.mean(all_times):.4f}s |\n"
        f.write(row)
    f.write("\n")

print("Saved writeup_clean_data.md")
